const GRAMMAR = [
  { id: "g001", pattern: "是...的", meaning: "emphatic construction for past events", usage: "Emphasizes the time, place, manner, or agent of a completed action. The sentence describes something that already happened.", example: "我是昨天來的。", exampleEn: "I came yesterday (emphasis on when).", category: "particles", level: "intermediate" },
  { id: "g002", pattern: "把 (bǎ)", meaning: "disposal construction — moves object before verb", usage: "Used to indicate that the subject disposes of or does something to the object. The object must be definite/known.", example: "請把這本書還給我。", exampleEn: "Please return this book to me.", category: "particles", level: "intermediate" },
  { id: "g003", pattern: "被 (bèi)", meaning: "passive voice marker", usage: "Indicates that the subject receives the action (passive). Often used when the result is undesirable or unexpected.", example: "我的錢包被偷了。", exampleEn: "My wallet was stolen.", category: "particles", level: "intermediate" },
  { id: "g004", pattern: "因為...所以", meaning: "because...therefore", usage: "Expresses a cause-and-effect relationship. Both clauses can stand alone, but together emphasize the relationship.", example: "因為下雨，所以我沒出門。", exampleEn: "Because it rained, I didn't go out.", category: "conjunctions", level: "elementary" },
  { id: "g005", pattern: "雖然...但是", meaning: "although...but", usage: "Expresses a concession — something is true, but another thing is also true and seems contradictory.", example: "雖然很貴，但是我還是買了。", exampleEn: "Although it was expensive, I still bought it.", category: "conjunctions", level: "intermediate" },
  { id: "g006", pattern: "如果...就", meaning: "if...then", usage: "Expresses a conditional relationship. 如果 introduces the condition, 就 introduces the result.", example: "如果明天下雨，我就不去了。", exampleEn: "If it rains tomorrow, I won't go.", category: "conjunctions", level: "intermediate" },
  { id: "g007", pattern: "不但...而且", meaning: "not only...but also", usage: "Adds additional information that goes beyond the first point, often escalating in degree.", example: "她不但聰明，而且很努力。", exampleEn: "She is not only smart, but also very hard-working.", category: "conjunctions", level: "intermediate" },
  { id: "g008", pattern: "越來越...", meaning: "more and more; increasingly", usage: "Indicates a gradual increase in degree or quantity over time.", example: "天氣越來越熱了。", exampleEn: "The weather is getting hotter and hotter.", category: "adverbs", level: "elementary" },
  { id: "g009", pattern: "有點 (yǒu diǎn)", meaning: "a little bit; somewhat (slightly negative)", usage: "Indicates a small degree. Often used for things that are slightly undesirable or inconvenient.", example: "這道菜有點鹹。", exampleEn: "This dish is a little salty.", category: "adverbs", level: "elementary" },
  { id: "g010", pattern: "比 (bǐ)", meaning: "comparison — more than; -er than", usage: "Used to make direct comparisons between two things. The structure is: A 比 B + adjective.", example: "他比我高。", exampleEn: "He is taller than me.", category: "comparison", level: "elementary" },
  { id: "g011", pattern: "了 (le)", meaning: "completed action or changed state", usage: "Attached to verbs to show completion, or at the end of sentences to show a change in situation. Context determines meaning.", example: "我吃飯了。", exampleEn: "I've eaten. / I ate.", category: "particles", level: "elementary" },
  { id: "g012", pattern: "過 (guò)", meaning: "past experience marker", usage: "Indicates that an action has been experienced at some unspecified time in the past. Like 'have ever done'.", example: "我去過台灣。", exampleEn: "I have been to Taiwan (before).", category: "particles", level: "elementary" },
  { id: "g013", pattern: "著 (zhe)", meaning: "continuous state; doing while...", usage: "Indicates an ongoing state or action. Also used to describe doing one action simultaneously with another.", example: "她笑著對我說話。", exampleEn: "She spoke to me while smiling.", category: "particles", level: "intermediate" },
  { id: "g014", pattern: "再 (zài)", meaning: "do again (future action)", usage: "Used for actions that will happen again in the future. Compare with 又 (yòu) which refers to repetition in the past.", example: "請再說一次。", exampleEn: "Please say it once more.", category: "adverbs", level: "elementary" },
  { id: "g015", pattern: "又 (yòu)", meaning: "did again (past); both...and", usage: "Refers to an action that was repeated in the past. Also used to show two simultaneous qualities.", example: "他又來了。", exampleEn: "He came again.", category: "adverbs", level: "elementary" },
  { id: "g016", pattern: "才 (cái)", meaning: "only then; just barely; not until", usage: "Indicates that something happened later than expected, or that a condition must be met first.", example: "學了一年，我才能說一點中文。", exampleEn: "After studying for a year, I could only speak a little Chinese.", category: "adverbs", level: "intermediate" },
  { id: "g017", pattern: "就 (jiù)", meaning: "then; right away; already; as soon as", usage: "Has many uses: indicating immediacy, fulfillment of a condition, or something happening sooner than expected.", example: "我一到家就睡了。", exampleEn: "As soon as I got home, I fell asleep.", category: "adverbs", level: "elementary" },
  { id: "g018", pattern: "一邊...一邊", meaning: "doing...while simultaneously doing", usage: "Describes two actions happening at the same time by the same subject.", example: "他一邊吃飯一邊看電視。", exampleEn: "He eats while watching TV.", category: "adverbs", level: "intermediate" },
  { id: "g019", pattern: "除了...以外", meaning: "except for; besides; in addition to", usage: "Can be exclusive (except for) or inclusive (in addition to). Context and rest of sentence determine meaning.", example: "除了他以外，大家都來了。", exampleEn: "Everyone came except for him.", category: "conjunctions", level: "intermediate" },
  { id: "g020", pattern: "越...越...", meaning: "the more...the more", usage: "Shows that as one thing increases, another thing increases proportionally.", example: "你越說，我越不懂。", exampleEn: "The more you say, the less I understand.", category: "adverbs", level: "intermediate" },
];
